public void testOperateNonSquareMatrix() {
    BigMatrix a = new BigMatrixImpl(new BigDecimal[][] {
            { new BigDecimal(2), new BigDecimal(3), new BigDecimal(4) },
            { new BigDecimal(1), new BigDecimal(0), new BigDecimal(2) }
    }, false);
    BigDecimal[] b = a.operate(new BigDecimal[] { new BigDecimal(1), new BigDecimal(2), new BigDecimal(3) });
    assertEquals(a.getRowDimension(), b.length);
    assertEquals(20.0, b[0].doubleValue(), 1.0e-12);
    assertEquals(7.0, b[1].doubleValue(), 1.0e-12);
}

public void testOperateNonSquareMatrix() {
    RealMatrix a = new RealMatrixImpl(new double[][] {
            { 2, 3, 4 },
            { 1, 0, 2 }
    }, false);
    double[] b = a.operate(new double[] { 1, 2, 3 });
    assertEquals(a.getRowDimension(), b.length);
    assertEquals(20.0, b[0], 1.0e-12);
    assertEquals(7.0, b[1], 1.0e-12);
}

public void testOperateSingleRowMatrix() {
    BigMatrix a = new BigMatrixImpl(new BigDecimal[][] {
            { new BigDecimal(5), new BigDecimal(10) }
    }, false);
    BigDecimal[] b = a.operate(new BigDecimal[] { new BigDecimal(2), new BigDecimal(3) });
    assertEquals(1, b.length);
    assertEquals(40.0, b[0].doubleValue(), 1.0e-12);
}

public void testOperateSingleRowMatrix() {
    RealMatrix a = new RealMatrixImpl(new double[][] {
            { 5, 10 }
    }, false);
    double[] b = a.operate(new double[] { 2, 3 });
    assertEquals(1, b.length);
    assertEquals(40.0, b[0], 1.0e-12);
}
